1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteInput {
9	  items: Item[];
10	}
11	
12	export interface QuoteResult {
13	  premium: number;
14	}
15	
16	const PROCESSING_FEE = 5;
17	const DEFAULT_BASE_PREMIUM = 100;
18	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	  rune: 25,
23	};
24	
25	export function quote(input: QuoteInput): QuoteResult {
26	  const firstItem = input.items[0];
27	  const basePremium = firstItem
28	    ? BASE_PREMIUM_BY_TYPE[firstItem.type] ?? DEFAULT_BASE_PREMIUM
29	    : 0;
30	  return { premium: basePremium + PROCESSING_FEE };
31	}
